const { SPECIFIC_DEVICE_TYPES } = require('../constants/device');
const { ENDS_WITH_DEVICE_TYPE_REGEX } = require('../constants/regexs');

/**
 * @typedef { keyof typeof import('../constants/device').DEVICE_TYPES } DeviceType
 * @typedef { import('../page/paths').Paths } Paths
 * @typedef { keyof typeof SPECIFIC_DEVICE_TYPES } SpecificDeviceType
 * @typedef { { [device in DeviceType]?: Paths } } PagePathsByDevice
 *
 * @typedef { object } DeviceData
 * @property { SpecificDeviceType | null } device - Device found or empty string
 * @property { Paths } paths - Device paths for a certain page
 */

/**
 * @private
 * Returns the first device type and the device page paths using
 * the device order of priority {@link SPECIFIC_DEVICE_TYPES}
 * @param { PagePathsByDevice } pagePaths - Set of paths by device of a certain page
 * @returns { DeviceData } Device type and device paths
 *
 * @todo Change example when islands change to type string[]
 * @example
 * const paths = {
 *  tablet: {
 *    client: 'home.tablet',
 *    view: 'home.tablet.js',
 *    style: 'home.tablet.scss'
 *  },
 *  mobile: {
 *    client: 'home.mobile',
 *    view: 'home.mobile.js',
 *    islands: ['nordic-island-counter'],
 *  }
 * };
 * getPriorityDeviceData(paths);
 * => {
 *      deviceType: 'mobile',
 *      paths: {
 *        client: 'home.mobile',
 *        view: 'home.mobile.js',
 *        islands: ['nordic-island-counter'],
 *      },
 *    }
 */
const getPriorityDeviceData = (pagePaths) => {
  /**
   * @type { SpecificDeviceType | null }
   */
  const device =
    SPECIFIC_DEVICE_TYPES[
      Object.keys(SPECIFIC_DEVICE_TYPES).find((key) => !!pagePaths[key]?.view)
    ] || null;

  return { device, paths: device ? pagePaths[device] : null };
};

/**
 * @param { string } client
 * @returns { string } Base client name
 */
const removeDeviceFromClientName = (client) =>
  client.replace(ENDS_WITH_DEVICE_TYPE_REGEX, '');

module.exports = {
  getPriorityDeviceData,
  removeDeviceFromClientName,
};
